33	const basePremium = (item: Item): number => {
34	  if (!(item.type in BASE_PREMIUMS)) {
35	    throw new Error(`Unknown item type: ${item.type}`);
36	  }
37	  return BASE_PREMIUMS[item.type];
38	};
