40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	const BLOCK_SIZE = 3;
42	const BLOCK_PRICE = 60;
43	
44	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
45	
46	const countByType = (items: Item[]): Record<string, number> =>
47	  items.reduce<Record<string, number>>((counts, item) => {
48	    counts[item.type] = (counts[item.type] ?? 0) + 1;
49	    return counts;
50	  }, {});
51	
52	const componentGroupPremium = (type: string, count: number): number =>
53	  count === BLOCK_SIZE ? BLOCK_PRICE : count * basePremium({ type });
54	
55	const componentsPremium = (components: Item[]): number => {
56	  const counts = countByType(components);
57	  return Object.entries(counts).reduce(
58	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
59	    0,
60	  );
61	};
