63	const CURSED_SURCHARGE_RATE = 0.5;
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	const HIGH_ENCHANTMENT_RATE = 0.3;
66	const FIRST_INSURANCE_RATE = 0.1;
67	const LOYALTY_YEARS_THRESHOLD = 2;
68	const LOYALTY_DISCOUNT_RATE = 0.2;
69	const FOLLOWUP_DISCOUNT_RATE = 0.15;
70	
71	const itemSurcharges = (item: Item): number => {
72	  const base = basePremium(item);
73	  let extras = 0;
74	  if (item.cursed) extras += base * CURSED_SURCHARGE_RATE;
75	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
76	    extras += base * HIGH_ENCHANTMENT_RATE;
77	  }
78	  return extras;
79	};
