81	const itemsBasePremium = (items: Item[]): number => {
82	  const mainItems = items.filter((i) => !isComponent(i));
83	  const components = items.filter(isComponent);
84	  const mainTotal = mainItems.reduce(
85	    (sum, item) => sum + basePremium(item) + itemSurcharges(item),
86	    0,
87	  );
88	  return mainTotal + componentsPremium(components);
89	};
