91	const policyBaseSum = (items: Item[]): number => {
92	  const mainBase = items.filter((i) => !isComponent(i)).reduce((s, i) => s + basePremium(i), 0);
93	  const compBase = componentsPremium(items.filter(isComponent));
94	  return mainBase + compBase;
95	};
