97	const policyModifiers = (
98	  customer: Customer,
99	  policyBase: number,
100	  isFollowUp: boolean,
101	): number => {
102	  let modifiers = policyBase * FIRST_INSURANCE_RATE;
103	  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
104	    modifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
105	  }
106	  if (isFollowUp) {
107	    modifiers -= policyBase * FOLLOWUP_DISCOUNT_RATE;
108	  }
109	  return modifiers;
110	};
111	
112	const computeQuotePremium = (
113	  customer: Customer,
114	  items: Item[],
115	  isFollowUp: boolean,
116	): number => {
117	  const itemsWithSurcharges = itemsBasePremium(items);
118	  const policyBase = policyBaseSum(items);
119	  const raw =
120	    itemsWithSurcharges + policyModifiers(customer, policyBase, isFollowUp) + PROCESSING_FEE;
121	  return Math.ceil(raw);
122	};
